import React, { useState, useEffect } from "react";
import MapView from "../components/MapView";
import { io } from "socket.io-client";
import "./journey.css";

const socket = io("http://localhost:5000");

function Journey() {
  const [destination, setDestination] = useState("");
  const [originCoords, setOriginCoords] = useState(null);
  const [destinationCoords, setDestinationCoords] = useState(null);
  const [info, setInfo] = useState(null);
  const [voiceOn, setVoiceOn] = useState(false);

  /* 📍 LIVE LOCATION */
  useEffect(() => {
    const watchId = navigator.geolocation.watchPosition(
      (pos) => {
        const lat = pos.coords.latitude;
        const lon = pos.coords.longitude;

        const current = { lat, lng: lon };
        setOriginCoords(current);

        // send to backend
        fetch("http://localhost:5000/location", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ lat, lon }),
        });

        // socket
        socket.emit("location", { lat, lon });
      },
      (err) => console.log(err),
      { enableHighAccuracy: true }
    );

    return () => navigator.geolocation.clearWatch(watchId);
  }, []);

  /* 🎯 SET DESTINATION */
  const setDestinationFunc = () => {
    if (!destination || !originCoords) return alert("Enter destination");

    setDestinationCoords({
      lat: originCoords.lat + 0.01,
      lng: originCoords.lng + 0.01,
    });
  };

  /* 🚨 SOS */
  const triggerEmergency = async () => {
    if (!originCoords) return alert("Location not available");

    await fetch("http://localhost:5000/sos", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        lat: originCoords.lat,
        lon: originCoords.lng,
      }),
    });

    alert("🚨 SOS Sent!");
  };

  /* 🎤 VOICE SOS */
  useEffect(() => {
    if (!voiceOn) return;

    const SpeechRecognition =
      window.SpeechRecognition || window.webkitSpeechRecognition;

    if (!SpeechRecognition) return;

    const recognition = new SpeechRecognition();
    recognition.continuous = true;

    recognition.onresult = (event) => {
      const text =
        event.results[event.results.length - 1][0].transcript.toLowerCase();

      if (text.includes("help me")) {
        triggerEmergency();
      }
    };

    recognition.start();

    return () => recognition.stop();
  }, [voiceOn]);

  return (
    <div className="app">

      {/* HEADER */}
      <div className="header-card glass">
        <div className="shield pulse">🛡️</div>
        <h2>Women Safety Monitor</h2>
        <p>Real-time journey protection system</p>
      </div>

      {/* FORM */}
      <div className="section-card glass">

        <h3>🚗 Journey Setup</h3>

        <input
          placeholder="Enter destination"
          value={destination}
          onChange={(e) => setDestination(e.target.value)}
        />

        <div className="btn-group">
          <button className="primary-btn" onClick={setDestinationFunc}>
            📍 Set Destination
          </button>

          <button className="primary-btn active">
            ✈ Start Journey
          </button>
        </div>

      </div>

      {/* MAP */}
      <div className="map-wrap glass">
        <MapView
          origin={originCoords}
          destination={destinationCoords}
          setInfo={setInfo}
        />
      </div>

      {/* STATUS */}
      <div className="status glass">

        <div className="status-header">
          🛡 STATUS
          <span className={originCoords ? "safe" : "danger"}>
            {originCoords ? "SAFE" : "NO GPS"}
          </span>
        </div>

        <div className="status-row">
          📍 {originCoords
            ? `${originCoords.lat}, ${originCoords.lng}`
            : "Fetching..."}
        </div>

      </div>

      {/* SOS */}
      <button className="sos-btn" onClick={triggerEmergency}>
        🚨 SOS
      </button>

      {/* ACTIONS */}
      <div className="actions">

        <button onClick={() => window.open("tel:112")}>📞</button>

        <button
          onClick={() =>
            originCoords &&
            window.open(
              `https://maps.google.com/?q=${originCoords.lat},${originCoords.lng}`
            )
          }
        >
          📤
        </button>

        <button onClick={() => setVoiceOn(!voiceOn)}>
          🎤 {voiceOn ? "ON" : "OFF"}
        </button>

        <button>🚓</button>

      </div>

    </div>
  );
}

export default Journey;
